新手提示：Function Calling 的核心优势是格式保障——与传统文本输出不同，LLM 被"锁死"在你
的 schema 框架内，不会输出 "人名：马云" 这种后处理困难的自由文本。
# 定义函数接口 —— 告诉 LLM "你必须按这个格式输出"
functions = [{
"name": "extract_entities",
"description": "从输入文本中抽取命名实体",
"parameters": {
"type": "object",
"properties": {
"entities": {
"type": "array",
"items": {
"type": "object",
"properties": {
"text": {"type": "string", "description": "实体原文"},
"type": {
"type": "string",
"enum": ["PER", "LOC", "ORG"],
"description": "实体类型"
},
"start": {"type": "integer", "description": "起始位置"},
"end": {"type": "integer", "description": "结束位置"}
},
"required": ["text", "type", "start", "end"]
}]
# 调用 LLM
response = llm.chat(
messages=[{"role": "user", "content": "马云在杭州创立阿里巴巴。"}],
functions=functions,
function_call={"name": "extract_entities"}  # 强制调用此函数
# LLM 必须返回严格符合 schema 的结构
# 输出：{"entities": [
#     {"text": "马云", "type": "PER", "start": 0, "end": 2},
#     {"text": "杭州", "type": "LOC", "start": 3, "end": 5},
#     {"text": "阿里巴巴", "type": "ORG", "start": 6, "end": 10}
# ]}

F1 = 同时衡量"抓得全不全"和"抓得准不准"，暴露出 Accuracy 掩盖的问题。

class MultiTaskModel(nn.Module):
def __init__(self, bert):
super().__init__()
self.bert = bert
self.topic_head = nn.Linear(768, 10)  # 主题10分类
self.sentiment_head = nn.Linear(768, 3)  # 情感3分类
self.risk_head = nn.Linear(768, 2)  # 风险2分类
def forward(self, input_ids, attention_mask, task='topic'):
outputs = self.bert(input_ids, attention_mask=attention_mask)
cls_vec = outputs.last_hidden_state[:, 0, :]
if task == 'topic':
return self.topic_head(cls_vec)
elif task == 'sentiment':
return self.sentiment_head(cls_vec)
elif task == 'risk':
return self.risk_head(cls_vec)

